    33→SPIFFEValidator::SPIFFEValidator(const Envoy::Ssl::CertificateValidationContextConfig* config,
    34→                                 SslStats& stats,
    35→                                 Server::Configuration::CommonFactoryContext& context)
    36→    : stats_(stats), time_source_(context.timeSource()) {
    37→  ASSERT(config != nullptr);
    38→  allow_expired_certificate_ = config->allowExpiredCertificate();
    39→
    40→  SPIFFEConfig message;
    41→  Config::Utility::translateOpaqueConfig(config->customValidatorConfig().value().typed_config(),
    42→                                         ProtobufMessage::getStrictValidationVisitor(), message);
    43→
    44→  if (!config->subjectAltNameMatchers().empty()) {
    45→    for (const auto& matcher : config->subjectAltNameMatchers()) {
    46→      if (matcher.san_type() ==
    47→          envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::URI) {
    48→        // Only match against URI SAN since SPIFFE specification does not restrict values in other
    49→        // SAN types. See the discussion: https://github.com/envoyproxy/envoy/issues/15392
    50→        // TODO(pradeepcrao): Throw an exception when a non-URI matcher is encountered after the
    51→        // deprecated field match_subject_alt_names is removed
    52→        subject_alt_name_matchers_.emplace_back(createStringSanMatcher(matcher, context));
    53→      }
    54→    }
    55→  }
    56→
    57→  const auto size = message.trust_domains().size();
    58→  trust_bundle_stores_.reserve(size);
    59→  for (auto& domain : message.trust_domains()) {
    60→    if (trust_bundle_stores_.find(domain.name()) != trust_bundle_stores_.end()) {
    61→      throw EnvoyException(absl::StrCat(
    62→          "Multiple trust bundles are given for one trust domain for ", domain.name()));
    63→    }
    64→
    65→    auto cert = THROW_OR_RETURN_VALUE(
    66→        Config::DataSource::read(domain.trust_bundle(), true, config->api()), std::string);
    67→    bssl::UniquePtr<BIO> bio(BIO_new_mem_buf(const_cast<char*>(cert.data()), cert.size()));
    68→    RELEASE_ASSERT(bio != nullptr, "");
