   108→absl::Status SPIFFEValidator::addClientValidationContext(SSL_CTX* ctx, bool) {
   109→  // Use a generic lambda to be compatible with BoringSSL before and after
   110→  // https://boringssl-review.googlesource.com/c/boringssl/+/56190
   111→  bssl::UniquePtr<STACK_OF(X509_NAME)> list(
   112→      sk_X509_NAME_new([](auto* a, auto* b) -> int { return X509_NAME_cmp(*a, *b); }));
   113→
   114→  for (auto& ca : ca_certs_) {
   115→    X509_NAME* name = X509_get_subject_name(ca.get());
   116→
   117→    // Check for duplicates.
   118→    if (sk_X509_NAME_find(list.get(), nullptr, name)) {
   119→      continue;
   120→    }
   121→
   122→    bssl::UniquePtr<X509_NAME> name_dup(X509_NAME_dup(name));
   123→    if (name_dup == nullptr || !sk_X509_NAME_push(list.get(), name_dup.release())) {
   124→      return absl::InvalidArgumentError("Failed to load trusted client CA certificate");
   125→    }
   126→  }
   127→  SSL_CTX_set_client_CA_list(ctx, list.release());
   128→  return absl::OkStatus();
   129→}
