   149→bool SPIFFEValidator::verifyCertChainUsingTrustBundleStore(X509& leaf_cert,
   150→                                                           STACK_OF(X509)* cert_chain,
   151→                                                           X509_VERIFY_PARAM* verify_param,
   152→                                                           std::string& error_details) {
   153→  if (!SPIFFEValidator::certificatePrecheck(&leaf_cert)) {
   154→    error_details = "verify cert failed: cert precheck";
   155→    stats_.fail_verify_error_.inc();
   156→    return false;
   157→  }
   158→
   159→  auto trust_bundle = getTrustBundleStore(&leaf_cert);
   160→  if (!trust_bundle) {
   161→    error_details = "verify cert failed: no trust bundle store";
   162→    stats_.fail_verify_error_.inc();
   163→    return false;
   164→  }
   165→
   166→  // Set the trust bundle's certificate store on a copy of the context, and do the verification.
   167→  bssl::UniquePtr<X509_STORE_CTX> new_store_ctx(X509_STORE_CTX_new());
   168→  if (!X509_STORE_CTX_init(new_store_ctx.get(), trust_bundle, &leaf_cert, cert_chain) ||
   169→      !X509_VERIFY_PARAM_set1(X509_STORE_CTX_get0_param(new_store_ctx.get()), verify_param)) {
   170→    error_details = "verify cert failed: init and setup X509_STORE_CTX";
   171→    stats_.fail_verify_error_.inc();
   172→    return false;
   173→  }
   174→  if (allow_expired_certificate_) {
   175→    CertValidatorUtil::setIgnoreCertificateExpiration(new_store_ctx.get());
   176→  }
   177→  auto ret = X509_verify_cert(new_store_ctx.get());
   178→  if (!ret) {
   179→    error_details = absl::StrCat("verify cert failed: ",
   180→                                 Utility::getX509VerificationErrorInfo(new_store_ctx.get()));
   181→    stats_.fail_verify_error_.inc();
   182→    return false;
   183→  }
   184→
   185→  // Do SAN matching.
   186→  const bool san_match = subject_alt_name_matchers_.empty() ? true : matchSubjectAltName(leaf_cert);
   187→  if (!san_match) {
   188→    error_details = "verify cert failed: SAN match";
   189→    stats_.fail_verify_san_.inc();
   190→  }
   191→  return san_match;
   192→}
