   194→ValidationResults SPIFFEValidator::doVerifyCertChain(
   195→    STACK_OF(X509)& cert_chain, Ssl::ValidateResultCallbackPtr /*callback*/,
   196→    const Network::TransportSocketOptionsConstSharedPtr& /*transport_socket_options*/,
   197→    SSL_CTX& ssl_ctx, const CertValidator::ExtraValidationContext& /*validation_context*/,
   198→    bool /*is_server*/, absl::string_view /*host_name*/) {
   199→  if (sk_X509_num(&cert_chain) == 0) {
   200→    stats_.fail_verify_error_.inc();
   201→    return {ValidationResults::ValidationStatus::Failed,
   202→            Envoy::Ssl::ClientValidationStatus::NotValidated, absl::nullopt,
   203→            "verify cert failed: empty cert chain"};
   204→  }
   205→  X509* leaf_cert = sk_X509_value(&cert_chain, 0);
   206→  std::string error_details;
   207→  bool verified = verifyCertChainUsingTrustBundleStore(*leaf_cert, &cert_chain,
   208→                                                       SSL_CTX_get0_param(&ssl_ctx), error_details);
   209→  return verified ? ValidationResults{ValidationResults::ValidationStatus::Successful,
   210→                                      Envoy::Ssl::ClientValidationStatus::Validated, absl::nullopt,
   211→                                      absl::nullopt}
   212→                  : ValidationResults{ValidationResults::ValidationStatus::Failed,
   213→                                      Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt,
   214→                                      error_details};
   215→}
