   217→X509_STORE* SPIFFEValidator::getTrustBundleStore(X509* leaf_cert) {
   218→  bssl::UniquePtr<GENERAL_NAMES> san_names(static_cast<GENERAL_NAMES*>(
   219→      X509_get_ext_d2i(leaf_cert, NID_subject_alt_name, nullptr, nullptr)));
   220→  if (!san_names) {
   221→    return nullptr;
   222→  }
   223→
   224→  std::string trust_domain;
   225→  for (const GENERAL_NAME* general_name : san_names.get()) {
   226→    if (general_name->type != GEN_URI) {
   227→      continue;
   228→    }
   229→
   230→    const std::string san = Utility::generalNameAsString(general_name);
   231→    trust_domain = SPIFFEValidator::extractTrustDomain(san);
   232→    // We can assume that valid SVID has only one URI san.
   233→    break;
   234→  }
   235→
   236→  if (trust_domain.empty()) {
   237→    return nullptr;
   238→  }
   239→
   240→  auto target_store = trust_bundle_stores_.find(trust_domain);
   241→  return target_store != trust_bundle_stores_.end() ? target_store->second.get() : nullptr;
   242→}
