    22→                                                              TimeSource& time_source) {
    23→  Envoy::Ssl::CertificateDetailsPtr certificate_details =
    24→      std::make_unique<envoy::admin::v3::CertificateDetails>();
    25→  certificate_details->set_path(path);
    26→  certificate_details->set_serial_number(Utility::getSerialNumberFromCertificate(*cert));
    27→  const auto days_until_expiry = Utility::getDaysUntilExpiration(cert, time_source).value_or(0);
    28→  certificate_details->set_days_until_expiration(days_until_expiry);
    29→
    30→  ProtobufWkt::Timestamp* valid_from = certificate_details->mutable_valid_from();
    31→  TimestampUtil::systemClockToTimestamp(Utility::getValidFrom(*cert), *valid_from);
    32→  ProtobufWkt::Timestamp* expiration_time = certificate_details->mutable_expiration_time();
    33→  TimestampUtil::systemClockToTimestamp(Utility::getExpirationTime(*cert), *expiration_time);
    34→
    35→  for (auto& dns_san : Utility::getSubjectAltNames(*cert, GEN_DNS)) {
    36→    envoy::admin::v3::SubjectAlternateName& subject_alt_name =
    37→        *certificate_details->add_subject_alt_names();
    38→    subject_alt_name.set_dns(dns_san);
