    53→bool Utility::labelWildcardMatch(absl::string_view dns_label, absl::string_view pattern) {
    54→  constexpr char glob = '*';
    55→  // Check the special case of a single * pattern, as it's common.
    56→  if (pattern.size() == 1 && pattern[0] == glob) {
    57→    return true;
    58→  }
    59→  // Only valid if wildcard character appear once.
    60→  if (std::count(pattern.begin(), pattern.end(), glob) == 1) {
    61→    std::vector<absl::string_view> split_pattern = absl::StrSplit(pattern, glob);
    62→    return (pattern.size() <= dns_label.size() + 1) &&
    63→           absl::StartsWith(dns_label, split_pattern[0]) &&
    64→           absl::EndsWith(dns_label, split_pattern[1]);
    65→  }
    66→  return false;
    67→}
