   386→absl::string_view Utility::getCertificateExtensionValue(X509& cert,
   387→                                                        absl::string_view extension_name) {
   388→  bssl::UniquePtr<ASN1_OBJECT> oid(
   389→      OBJ_txt2obj(std::string(extension_name).c_str(), 1 /* don't search names */));
   390→  if (oid == nullptr) {
   391→    return {};
   392→  }
   393→
   394→  int pos = X509_get_ext_by_OBJ(&cert, oid.get(), -1);
   395→  if (pos < 0) {
   396→    return {};
   397→  }
   398→
   399→  X509_EXTENSION* extension = X509_get_ext(&cert, pos);
   400→  if (extension == nullptr) {
   401→    return {};
   402→  }
   403→
   404→  const ASN1_OCTET_STRING* octet_string = X509_EXTENSION_get_data(extension);
   405→  RELEASE_ASSERT(octet_string != nullptr, "");
   406→
   407→  // Return the entire DER-encoded value for this extension. Correct decoding depends on
   408→  // knowledge of the expected structure of the extension's value.
   409→  const unsigned char* octet_string_data = ASN1_STRING_get0_data(octet_string);
   410→  const int octet_string_length = ASN1_STRING_length(octet_string);
   411→
   412→  return {reinterpret_cast<const char*>(octet_string_data),
   413→          static_cast<absl::string_view::size_type>(octet_string_length)};
   414→}
