   195→bool DefaultCertValidator::verifyCertAndUpdateStatus(
   196→    X509* leaf_cert, const Network::TransportSocketOptions* transport_socket_options,
   197→    Envoy::Ssl::ClientValidationStatus& detailed_status, std::string* error_details,
   198→    uint8_t* out_alert) {
   199→  Envoy::Ssl::ClientValidationStatus validated =
   200→      verifyCertificate(leaf_cert,
   201→                        transport_socket_options != nullptr
   202→                            ? transport_socket_options->verifySubjectAltNameListOverride()
   203→                            : std::vector<std::string>{},
   204→                        subject_alt_name_matchers_, error_details, out_alert);
   205→
   206→  if (detailed_status == Envoy::Ssl::ClientValidationStatus::NotValidated ||
   207→      validated != Envoy::Ssl::ClientValidationStatus::NotValidated) {
   208→    detailed_status = validated;
